import{_ as i,o as r,c as l,ag as s}from"./chunks/framework.DXGyWiRo.js";const n="/images/uebung092.jpg",h=JSON.parse('{"title":"Übung Lektion 55","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung55.md","filePath":"lektionen/uebung55.md"}'),t={name:"lektionen/uebung55.md"};function a(P,e,o,p,u,d){return r(),l("div",null,[...e[0]||(e[0]=[s('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-55" tabindex="-1">Übung Lektion 55 <a class="header-anchor" href="#ubung-lektion-55" aria-label="Permalink to &quot;Übung Lektion 55&quot;">​</a></h1><p>Bestimmen und übersetzen Sie schriftlich folgende formen und bilden Sie die entsprechenden Formen des a-Aorist:</p><ol><li>दोक्ष्यन्ति - दुष् 4P 3.pl.Fut.P sie werden verderben - अदुषन्</li><li>बुबोध - बुध् 1U 1.3.sg.Perf.P ich / er erwachte - अबुधम् । अबुधत्</li><li>क्रुध्यसि - क्रुध् 4P 2.sg.Ind.Präs.P du zürnst - अक्रुधः</li><li>तोक्ष्यथ - तुष् 4P 2.pl.Fut.P ihr werdet zufrieden sein - अतुषत</li><li>कुप्यामः - कुप् 4P 1.pl.Ind.Präs.P wir zürnen - अकुपाम</li><li>आप - आप् 5P 1.3.sg.2.pl.Perf.P ich / er / ihr erlangte / erlangtet - आपम् । आपत् । आपत</li><li>जग्मुः - गम् 1P 3.pl.Perf.P sie gingen - अगमन्</li><li>छेत्स्यसि - छिद् 7U 2.sg.Fut.P du wirst abschneiden - अच्छिदः</li><li>पश्यथ - दृश् 4P 2.pl.Ind.Präs.P ihr seht - अदर्शत</li><li>ध्रोक्ष्यामि - द्रुह् 4P 1.sg.Fut.P ich werde schädigen - अद्रुहम्</li><li>नेश - नश् 4P 2.pl.Perf.P ihr gingt verloren -अनशत</li><li>भिन्त्थ - भिद् 7U 2.pl.Ind.Präs.P ihr spaltet - अभिदत</li><li>भ्राम्यामः - भ्रम् 4P 1.pl.Ind.Präs.P wir irren umher - अभ्रमाम</li><li>मुन्चति - मुच् 6U 2.sg.Ind.Präs.P er lässt los - अमुचत्</li><li>मुह्यसि - मुह् 4P 2.sg.Ind.Präs.P du irrst - अमुहः</li><li>अरोदीत् - रुद् 2P 3.sg.Impf.P er heulte - अरुदत्</li><li>रुरोधिथ - रुध् 7U 2.sg.Perf.P du stopptest - अरुधः</li><li>श्राम्यन्ति - श्रम् 4P 3.pl.Ind.Präs.P sie mühen sich ab - अश्रमन्</li><li>विन्दथ - विद् 6U 2.pl.Ind.Präs.P ihr findet - अविदत</li><li>असीदन् -सद् 1P 3.pl.Impf.P sie saßen - असदन्</li><li>वर्तामहे (a-Aor.: P) - वृत् 1Ā 1.pl.Ind.Präs.Ā wir befinden uns - अवृताम</li><li>अशात् - शास् 2P 3.sg.Impf.P er befahl - अशिषत्</li><li>सेक्ष्यसे - शिच् 6U 2.sg.Fut.Ā du wirst im eigenen Interesse beträufeln - असिचथाः</li><li>अयुनक् - युज् 7U 2.3.sg.Impf.P du hast / er hat angeschirrt - अयुजः । अयुजत्</li><li>आरिथ - ऋ 3P 2.sg.Perf.P du bist gegangen - आरः</li><li>अक्लिद्यन् - क्लिद् 4P 3.pl.Impf.P sie wurden feucht - अक्लिदन्</li><li>अजीर्यम् (Aor.: hochstufig) - जॄ 4P 1.sg.Impf.P ich alterte - अजरम्</li><li>लुम्पति - लुप् 6U 3.sg.Ind.Präs.P er bricht - अलुपत्</li><li>अशाम्यत - शम् 4P 2.pl.Impf.P ihr wurdet ruhig - अशमत</li><li>अशोभथाः  (a-Aor.: P) - शुभ् 1Ā 2.sg.Impf.Ā du warst schön - अशुभः</li><li>अशुष्याम - शुष् 4P 1.pl.Impf.P wir wurden trocken - अशुषाम</li><li>सिष्णेह - स्निह् 4P 1.3.sg.Perf.P ich / er liebte - अस्निहम् । अस्निहत्</li></ol><p><img src="'+n+'" alt=""><br> Abb.: अशोभथाः । अशुभः ॥<br> [Bildquelle: said&amp;done. -- <a href="http://www.flickr.com/photos/faraz27989/245321480/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/faraz27989/245321480/</a>. -- Zugriff am 2009-03-11. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p>',5)])])}const c=i(t,[["render",a]]);export{h as __pageData,c as default};
